Rule.Source:
import sailpoint.api.IdentityService;
  import sailpoint.api.Workflower;
  import sailpoint.object.Attributes;
  import sailpoint.object.Application;
  import sailpoint.object.Custom;
  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AbstractRequest;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningResult;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Workflow;
  import sailpoint.tools.Util;
  import org.apache.log4j.Logger;

  //import sailpoint.connector.ConnectorClassLoader;

  //ClassLoader currentCl = Thread.currentThread().getContextClassLoader();
  //ClassLoader bakcedUpCl = null;
  //if(currentCl instanceof ConnectorClassLoader){
    //bakcedUpCl = currentCl;
    //Thread.currentThread().setContextClassLoader(currentCl.getParent());
  //}

  Logger refLogger = Logger.getLogger("sailpoint.ascension.rules.gsuite.initilizeattributes");

  refLogger.trace("Entering AfterProvisioning For GSuite");

  if (plan != null) {

    refLogger.trace("plan is NOT NULL - Proceeding...");

    Identity refIdentity = plan.getIdentity();
    String identityName = refIdentity.getName();

    String samAccountName = refIdentity.getAttribute("samAccountName");

    String appName = application.getName(); 

    ProvisioningPlan.AccountRequest accReq = plan.getAccountRequest(appName);

    ProvisioningResult accReqResult = accReq.getResult();
    String accReqStatus = accReqResult.getStatus();

    boolean hasADLink = hasADLink(refIdentity);

    if (accReq != null && hasADLink) {

      refLogger.trace("accReq is NOT NULL; And refIdentity has AD link - Proceeding...");

      if (AccountRequest.Operation.Create.equals(accReq.getOperation()) && Util.nullSafeCaseInsensitiveEq(accReqStatus, "committed")) {

        refLogger.trace("accReq Operation is Create - Proceeding...");

        String primaryEmail = accReq.getAttributeRequest("primaryEmail").getValue(context);
        String prefix = primaryEmail.replaceAll("@.*","").trim();
        String suffix = primaryEmail.replaceAll(".*.@","").trim();
        String orgUnitPath = accReq.getAttributeRequest("orgUnitPath").getValue(context);
        String ntAccountName = determineNTAccountName(refIdentity, samAccountName);
        String ea6 = determineEA6(refIdentity);
        String ea40 = determineEA40(orgUnitPath);
        String targetApp = determineTargetADApp(refIdentity, samAccountName);
        String targetDN = determineTargetDN(refIdentity, samAccountName);
        boolean targetConflict = checkTargetConflict(refIdentity, samAccountName);

        //Trigger Workflow. @param: identityName, primaryEmail, prefix, ea40, orgUnitPath, samAccountName, ntAccountName, targetApp, targetDN

        Workflow refWorkflow = context.getObjectByName(Workflow.class, "Ascension-Workflow-AfterProvisioning-GSuite");

        Workflower flower = new Workflower(context);

        Map workflowParams = new HashMap();

        workflowParams.put("identityName",identityName);
        workflowParams.put("primaryEmail",primaryEmail);
        workflowParams.put("prefix",prefix);
        workflowParams.put("suffix",suffix);
        workflowParams.put("ea6",ea6);
        workflowParams.put("ea40",ea40);
        workflowParams.put("orgUnitPath",orgUnitPath);
        workflowParams.put("samAccountName",samAccountName);
        workflowParams.put("ntAccountName",ntAccountName);
        workflowParams.put("targetApp",targetApp);
        workflowParams.put("targetDN",targetDN);
        workflowParams.put("targetConflict",targetConflict);

        flower.launchSafely(refWorkflow, "AfterProvisioning-GSuite-" + identityName, workflowParams);

        //Send Notifications for GSuite Account Creation

        List requesters = plan.getRequesters();

        if (requesters != null && !requesters.isEmpty()) {

          EmailTemplate requesterTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-GSuite-NewAccount");
          EmailTemplate managerTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-GSuite-NewAccountManager");

          EmailOptions emailOps = new EmailOptions();

          Identity refManager = null;

          String toAddress = null;

          for (Identity requester : requesters) {

            refManager = refIdentity.getManager();

            //Check If Requester is Manager

            if (refManager != null && requester == refManager) {

              toAddress = requester.getEmail();

              Map emailArgs = new HashMap();

              emailArgs.put("managerFN", requester.getFirstname());
              emailArgs.put("identityName", refIdentity.getName());
              emailArgs.put("displayName", refIdentity.getDisplayName());
              emailArgs.put("primaryEmail", primaryEmail);

              if (Util.isNotNullOrEmpty(toAddress)) {

                emailOps = new EmailOptions(toAddress, emailArgs);

                context.sendEmailNotification(managerTemplate, emailOps);

              }

            } else {

              //If Requester is not Manager; Send notice to Manager as well

              toAddress = requester.getEmail();

              Map emailArgs = new HashMap();

              emailArgs.put("requesterFN", requester.getFirstname());
              emailArgs.put("identityName", refIdentity.getName());
              emailArgs.put("displayName", refIdentity.getDisplayName());
              emailArgs.put("primaryEmail", primaryEmail);

              if (Util.isNotNullOrEmpty(toAddress)) {

                emailOps = new EmailOptions(toAddress, emailArgs);

                context.sendEmailNotification(requesterTemplate, emailOps);

                if (refManager != null) {

                  toAddress = refManager.getEmail();

                  emailArgs = new HashMap();

                  emailArgs.put("managerFN", refManager.getFirstname());
                  emailArgs.put("identityName", refIdentity.getName());
                  emailArgs.put("displayName", refIdentity.getDisplayName());
                  emailArgs.put("primaryEmail", primaryEmail);

                  if (Util.isNotNullOrEmpty(toAddress)) {

                    emailOps = new EmailOptions(toAddress, emailArgs);

                    context.sendEmailNotification(managerTemplate, emailOps);

                  }

                }

              }

            }

          }

        } else {

          refManager = refIdentity.getManager();

          if (refManager != null && refManager != void) {

            EmailTemplate managerTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-GSuite-NewAccountManager");

            EmailOptions emailOps = new EmailOptions();

            toAddress = refManager.getEmail();

            emailArgs = new HashMap();

            emailArgs.put("managerFN", refManager.getFirstname());
            emailArgs.put("identityName", refIdentity.getName());
            emailArgs.put("displayName", refIdentity.getDisplayName());
            emailArgs.put("primaryEmail", primaryEmail);

            if (Util.isNotNullOrEmpty(toAddress)) {

              emailOps = new EmailOptions(toAddress, emailArgs);

              context.sendEmailNotification(managerTemplate, emailOps);

            }

          }

        }

      } else {

        refLogger.trace("accReq Operation is NOT Create; Or was NOT successful - END");

      }

    } else {

      refLogger.trace("accReq is NULL; Or refIdentity has no AD link - END");

    }

  } else {

    refLogger.trace("plan is NULL - END");

  }

  refLogger.trace("Exiting AfterProvisioning For GSuite");
